arguments.file_text:
@* Displays a single task with move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (CanMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeft" disabled="@IsMoving">← Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRight" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    [Parameter]
    public bool IsMoving { get; set; }
}

@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <input type="text" placeholder="Title" @bind="title" @bind:event="oninput" />
        <input type="text" placeholder="Assignee" @bind="assignee" @bind:event="oninput" />
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" @bind="dueDate" />
        <div class="form-actions">
            <button class="btn-save" @onclick="Save" disabled="@IsSaving">Save</button>
            <button class="btn-cancel" @onclick="Hide">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);

    private void Show() => IsVisible = true;

    private void Hide()
    {
        IsVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee))
            return;

        IsSaving = true;
        try
        {
            await OnTaskCreated.InvokeAsync((title.Trim(), assignee.Trim(), priority, dueDate));
            Hide();
        }
        finally
        {
            IsSaving = false;
        }
    }
}

