{"path": "/tmp/sv-56730842f41f4d999866364aacc3b6fb/Components/Board/KanbanColumn.razor", "file_text": "<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="task-count">@Tasks.Count</span>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="() => MoveLeft(task)"
                      OnMoveRight="() => MoveRight(task)" />
        }
    </div>
    <div class="column-footer">
        <AddTaskForm OnTaskCreated="HandleTaskCreated" />
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = "";

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public string? LeftColumnStatus { get; set; }

    [Parameter]
    public string? RightColumnStatus { get; set; }

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private int? movingTaskId;

    private async Task MoveLeft(TaskItem task)
    {
        if (LeftColumnStatus is null) return;
        movingTaskId = task.Id;
        try
        {
            await OnTaskMoved.InvokeAsync((task.Id, LeftColumnStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task MoveRight(TaskItem task)
    {
        if (RightColumnStatus is null) return;
        movingTaskId = task.Id;
        try
        {
            await OnTaskMoved.InvokeAsync((task.Id, RightColumnStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync(newTask);
    }
}
"}

