{"file_text": "@page "/board"
@using sv_56730842f41f4d999866364aacc3b6fb.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Project Board</h2>

@if (isLoading)
{
    <p class="loading-message">Loading tasks…</p>
}
else if (errorMessage is not null)
{
    <div class="error-message">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="kanban-board">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      RightColumnStatus="In Progress"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, "To Do")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      LeftColumnStatus="To Do"
                      RightColumnStatus="Done"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, "In Progress")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetFilteredTasks("Done")"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      LeftColumnStatus="In Progress"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var idx = allTasks.FindIndex(t => t.Id == move.TaskId);
            if (idx >= 0)
            {
                var old = allTasks[idx];
                allTasks[idx] = old with { Status = move.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated(
        (string Title, string Assignee, string Priority, DateTime DueDate) newTask,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                newTask.Title, newTask.Assignee, newTask.Priority, newTask.DueDate);
            // CreateTaskAsync returns a task with default status; ensure it matches the target column
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}
