+    private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
+            var idx = allTasks.FindIndex(t => t.Id == move.TaskId);
+            if (idx >= 0)
+            {
+                var old = allTasks[idx];
+                allTasks[idx] = old with { Status = move.NewStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private async Task HandleTaskCreated(
+        (string Title, string Assignee, string Priority, DateTime DueDate) newTask,
+        string status)
+    {
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(
+                newTask.Title, newTask.Assignee, newTask.Priority, newTask.DueDate);
+            // CreateTaskAsync returns a task with default status; ensure it matches the target column
+            allTasks.Add(created with { Status = status });
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to create task: {ex.Message}";
+        }
+    }
+}
+

