58. 
59.     private List<TaskItem> allTasks = new();
60.     private string searchText = "";
61.     private bool isLoading = true;
62.     private string? errorMessage;
63. 
64.     protected override async Task OnInitializedAsync()
65.     {
66.         await LoadTasks();
67.     }
68. 
69.     private async Task LoadTasks()
70.     {
71.         isLoading = true;
72.         errorMessage = null;
73.         try
74.         {
75.             allTasks = await TaskService.GetAllTasksAsync();
76.         }
77.         catch (Exception ex)
78.         {
79.             errorMessage = $"Failed to load tasks: {ex.Message}";
80.         }
81.         finally
82.         {
83.             isLoading = false;
84.         }
85.     }
86. 
87.     private List<TaskItem> GetFilteredTasks(string status)
88.     {
89.         var tasks = allTasks.Where(t => t.Status == status);
90.         if (!string.IsNullOrWhiteSpace(searchText))
91.         {
92.             tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
93.         }
94.         return tasks.ToList();
95.     }
96. 
97.     private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
98.     {
99.         try
100.         {
101.             await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
102.             var idx = allTasks.FindIndex(t => t.Id == move.TaskId);
103.             if (idx >= 0)
104.             {
105.                 var old = allTasks[idx];
106.                 allTasks[idx] = old with { Status = move.NewStatus };
107.             }
108.         }
109.         catch (Exception ex)
110.         {
111.             errorMessage = $"Failed to move task: {ex.Message}";
112.         }
113.     }
114. 
115.     private async Task HandleTaskCreated(
116.         (string Title, string Assignee, string Priority, DateTime DueDate) newTask,
117.         string status)
118.     {
119.         try
120.         {
121.             var created = await TaskService.CreateTaskAsync(
122.                 newTask.Title, newTask.Assignee, newTask.Priority, newTask.DueDate);
123.             // CreateTaskAsync returns a task with default status; ensure it matches the target column
124.             allTasks.Add(created with { Status = status });
125.         }
126.         catch (Exception ex)
127.         {
128.             errorMessage = $"Failed to create task: {ex.Message}";
129.         }
130.     }
131. }
