         <KanbanColumn ColumnName="In Progress"
                       Tasks="@GetFilteredTasks(StatusInProgress)"
                       CanMoveLeft="true"
                       CanMoveRight="true"
                       LeftColumnStatus="@StatusToDo"
                       RightColumnStatus="@StatusDone"
                       OnTaskMoved="HandleTaskMoved"
                       OnTaskCreated="@(args => HandleTaskCreated(args, StatusInProgress))" />

         <KanbanColumn ColumnName="Done"
                       Tasks="@GetFilteredTasks(StatusDone)"
                       CanMoveLeft="true"
                       CanMoveRight="false"
                       LeftColumnStatus="@StatusInProgress"
                       OnTaskMoved="HandleTaskMoved"
                       OnTaskCreated="@(args => HandleTaskCreated(args, StatusDone))" />
     </div>
 }

 @code {
     private const string StatusToDo = "To Do";
     private const string StatusInProgress = "In Progress";
     private const string StatusDone = "Done";

     private List<TaskItem> allTasks = new();
     private string searchText = "";
     private bool isLoading = true;
     private string? errorMessage;

     protected override async Task OnInitializedAsync()
     {
         await LoadTasks();
     }

     private async Task LoadTasks()
     {
         isLoading = true;
         errorMessage = null;
         try
         {
             allTasks = await TaskService.GetAllTasksAsync();
         }
         catch (Exception ex)
         {
             errorMessage = $"Failed to load tasks: {ex.Message}";
         }
         finally
         {
             isLoading = false;
         }
     }

     private List<TaskItem> GetFilteredTasks(string status)
     {
         var tasks = allTasks.Where(t => t.Status == status);
         if (!string.IsNullOrWhiteSpace(searchText))
         {
             tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
         }
         return tasks.ToList();
     }

     private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
     {
         try
         {
             await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
             var idx = allTasks.FindIndex(t => t.Id == move.TaskId);
             if (idx >= 0)
             {
                 var old = allTasks[idx];
                 allTasks[idx] = old with { Status = move.NewStatus };
             }
         }
         catch (Exception ex)
         {
             errorMessage = $"Failed to move task: {ex.Message}";
         }
     }

     private async Task HandleTaskCreated(
         (string Title, string Assignee, string Priority, DateTime DueDate) newTask,
         string status)
     {
         try
         {
             var created = await TaskService.CreateTaskAsync(
                 newTask.Title, newTask.Assignee, newTask.Priority, newTask.DueDate);
             // CreateTaskAsync returns a task with default status; ensure it matches the target column
             allTasks.Add(created with { Status = status });
         }
         catch (Exception ex)
         {
             errorMessage = $"Failed to create task: {ex.Message}";
         }
     }
 }

